// Processar anexos do email
const outputItems = [];

for (const item of $input.all()) {
  console.log('=== PROCESSANDO EMAIL ===');
  console.log('Subject:', item.json.subject);
  console.log('From:', item.json.from);

  if (item.binary && Object.keys(item.binary).length > 0) {
    console.log('Anexos encontrados:', Object.keys(item.binary));

    for (const [key, attachment] of Object.entries(item.binary)) {
      const fileName = attachment.fileName || attachment.name || key;
      const mimeType = attachment.mimeType || attachment.type || '';

      console.log(`Arquivo: ${fileName}`);
      console.log(`Tipo: ${mimeType}`);

      // Aceitar planilhas Excel
      if (fileName.toLowerCase().includes('.xls') || 
          mimeType.includes('sheet') ||
          mimeType.includes('excel')) {

        // Extrair número da carga - REGEX MELHORADA
        const subject = item.json.subject || '';

        // Tentar vários padrões:
        // 1. "carga 890", "carga-890", "carga_890"
        // 2. "lotes 890", "lote 890"
        // 3. Apenas números após hífen ou underline: "- 890", "_890"
        // 4. Qualquer número de 3+ dígitos
        let numeroCarga = null;

        const patterns = [
          /(?:carga|lote|lotes)[:\s_-]*(\d+)/i,
          /[:\s_-](\d{3,})/,
          /(\d{3,})/
        ];

        for (const pattern of patterns) {
          const match = subject.match(pattern) || fileName.match(pattern);
          if (match) {
            numeroCarga = parseInt(match[1]);
            console.log(`Número da carga encontrado: ${numeroCarga} (padrão: ${pattern})`);
            break;
          }
        }

        if (!numeroCarga) {
          console.error('Número da carga não encontrado');
          console.error('Subject:', subject);
          console.error('Filename:', fileName);
          continue;
        }

        outputItems.push({
          json: {
            emailFrom: item.json.from || '',
            emailSubject: item.json.subject || '',
            emailDate: item.json.receivedDateTime || new Date().toISOString(),
            fileName: fileName,
            numero_carga: numeroCarga,
            emailId: item.json.id || ''
          },
          binary: {
            data: attachment
          }
        });

        console.log(`✅ Planilha adicionada para carga ${numeroCarga}`);
      }
    }
  } else {
    console.log('AVISO: Nenhum anexo encontrado');
  }
}

if (outputItems.length === 0) {
  throw new Error('Nenhuma planilha de lotes encontrada');
}

console.log(`Total processado: ${outputItems.length}`);
return outputItems;

// Verificar se a carga existe e preparar dados
const anexo = $('Processar Anexos').item.json;
const cargasEncontradas = $input.all();

const cargaExiste = cargasEncontradas && 
                    cargasEncontradas.length > 0 && 
                    cargasEncontradas[0].json.numero_carga;

if (!cargaExiste) {
  console.log(`📦 Carga ${anexo.numero_carga} não existe - será criada`);
  return [{
    json: {
      numero_carga: anexo.numero_carga,
      deve_criar_carga: true,
      operacao: 'INSERT'
    },
    binary: $('Processar Anexos').item.binary
  }];
} else {
  console.log(`✅ Carga ${anexo.numero_carga} já existe`);
  return [{
    json: {
      numero_carga: anexo.numero_carga,
      deve_criar_carga: false,
      operacao: 'SKIP',
      carga_id: cargasEncontradas[0].json.id
    },
    binary: $('Processar Anexos').item.binary
  }];
}

// Processar dados da planilha de lotes
const numeroCarga = $('Processar Status Carga').item.json.numero_carga;
const vinculos = [];
const sosSet = new Set();
let totalItems = 0;

for (const item of $input.all()) {
  const row = item.json;

  // Extrair SO number (pode estar em diferentes campos)
  const soNumber = (row['SO Number'] || row['Sales Order'] || row['SO'] || row['Order Number'] || '').toString().trim();

  if (!soNumber) {
    console.log('Linha sem SO:', row);
    continue;
  }

  sosSet.add(soNumber);
  totalItems++;
}

// Criar um item para cada SO única
for (const soNumber of sosSet) {
  vinculos.push({
    json: {
      numero_carga: numeroCarga,
      so_number: soNumber,
      item_count: 1, // Será contado depois se necessário
      status: 'Consolidado',
      created_at: new Date().toISOString()
    }
  });
}

console.log(`=== RESUMO ===`);
console.log(`Carga: ${numeroCarga}`);
console.log(`Total SOs: ${sosSet.size}`);
console.log(`Total Items: ${totalItems}`);

// Adicionar summary no primeiro item
if (vinculos.length > 0) {
  vinculos[0].json.summary = {
    numero_carga: numeroCarga,
    total_sos: sosSet.size,
    total_items: totalItems
  };
}

return vinculos;

// Node: Preparar Dados do Log
const allItems = $input.all();

// Extrair métricas específicas baseado no workflow
let workflowMetrics = {};
let mainMessage = 'Workflow executado';

// 1 - Standard Daily Order
if ($workflow.name.includes('Standard Daily Order')) {
  const salesOrders = allItems.map(i => i.json.sales_order).filter(Boolean);
  workflowMetrics = {
    total_orders: salesOrders.length,
    sales_orders: salesOrders.slice(0, 10), // Primeiras 10 SOs
    total_value: allItems.reduce((sum, i) => sum + parseFloat(i.json.valor_total || 0), 0).toFixed(2)
  };
  mainMessage = `${salesOrders.length} pedidos processados`;
}

// 2 - Automated Daily Shipment
else if ($workflow.name.includes('Automated Daily Shipment')) {
  workflowMetrics = {
    total_shipments: allItems.length,
    tracking_count: allItems.filter(i => i.json.tracking_numbers).length
  };
  mainMessage = `${allItems.length} envios processados`;
}

// 3 - FedEx Scraper
else if ($workflow.name.includes('FedEx Scraper')) {
  workflowMetrics = {
    trackings_verified: allItems.length,
    at_warehouse: allItems.filter(i => i.json.is_at_warehouse).length
  };
  mainMessage = `${allItems.length} trackings verificados`;
}

// 4 - Tracking Pós-Armazém
else if ($workflow.name.includes('Tracking Pós-Armazém') || $workflow.name.includes('Tracking PÃ³s-ArmazÃ©m')) {
  workflowMetrics = {
    emails_processed: allItems.length,
    cargas_processadas: allItems.filter(i => i.json.numero_carga).length
  };
  mainMessage = `${allItems.length} emails de tracking processados`;
}

// 5 - Planilha de Lotes
else if ($workflow.name.includes('Planilha de Lotes')) {
  const summary = allItems[0]?.json?.summary || allItems[0]?.json;
  workflowMetrics = {
    numero_carga: summary?.numero_carga,
    total_sos: summary?.total_sos,
    total_items: summary?.total_items
  };
  mainMessage = `Carga ${summary?.numero_carga} processada com ${summary?.total_sos} SOs`;
}

// 6 - Bio-Rad Pedido
else if ($workflow.name.includes('Bio-Rad') && $workflow.name.includes('PEDIDO')) {
  const orderData = allItems[0]?.json;
  workflowMetrics = {
    order_number: orderData?.orderNumber || orderData?.order_number,
    total_items: orderData?.metrics?.totalItems || orderData?.total_items,
    total_value: orderData?.financial?.total || orderData?.total_value
  };
  mainMessage = `Pedido ${orderData?.orderNumber} registrado`;
}

// 7 - Bio-Rad Confirmação
else if ($workflow.name.includes('Bio-Rad') && $workflow.name.includes('CONFIRMAÇÃO')) {
  const orderData = allItems[0]?.json;
  workflowMetrics = {
    order_number: orderData?.orderNumber,
    confirmation_number: orderData?.confirmationNumber,
    status: orderData?.overallStatus,
    confirmed_items: orderData?.metrics?.confirmedItems,
    total_items: orderData?.metrics?.totalItems
  };
  mainMessage = `Confirmação ${orderData?.confirmationNumber} processada`;
}

// Fallback genérico
else {
  workflowMetrics = {
    items_count: allItems.length
  };
  mainMessage = `${allItems.length} items processados`;
}

// Retornar dados formatados
return [{
  json: {
    workflow_name: $workflow.name,
    workflow_id: $workflow.id,
    execution_id: $execution.id,
    level: 'info',
    message: mainMessage,
    data: workflowMetrics,
    performance: {
      duration_ms: null,
      items_processed: allItems.length
    },
    context: {
      execution_mode: $execution.mode,
      timestamp: new Date().toISOString()
    }
  }
}];

// Combinar resultados e gerar resumo
const allResults = $input.all();
const summary = allResults[0]?.json?.summary;

if (!summary) {
  return [{
    json: {
      status: 'completed',
      message: 'Processamento concluído',
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    status: 'success',
    numero_carga: summary.numero_carga,
    total_sos: summary.total_sos,
    total_items: summary.total_items,
    sos_processadas: allResults.length,
    timestamp: new Date().toISOString(),
    message: `Carga ${summary.numero_carga}: ${summary.total_sos} SOs vinculadas`
  }
}];
